/** Style function for the equipment overlay layer. Uses Temaki icons for points (SPEC-636). */
export function equipmentLayerStyleFn(feature) {
    const geomType = feature.getGeometry()?.getType();
    // Suppress child Point devices of grouped structures (they're shown as one device)
    // but keep polygon children visible for hit detection
    if (feature.get('_groupId') && geomType === 'Point') return null;
    
    const playground = feature.get('playground');
    const leisure    = feature.get('leisure');

    let color;
    if (playground && playground !== 'yes' && playground in objDevices) {
        const cat = objDevices[playground].category;
        color = objColors[cat] ?? objColors.fallback;
    } else if (leisure === 'fitness_station') {
        color = objColors.activity;
    } else if (leisure === 'pitch') {
        color = '#4a7c3f';
    } else {
        color = objColors.stationary;
    }

    const [r, g, b] = hexToRgb(color);
    const fillColor   = `rgba(${r},${g},${b},0.5)`;
    const strokeColor = `rgba(${r},${g},${b},1)`;

    // Helper to resolve icon name from objFeatures match
    function getIconFromObjFeatures(feature) {
        for (const featKey in objFeatures) {
            const feat = objFeatures[featKey];
            if (feat.icon) {
                const tags = feat.tags;
                let matches = true;
                for (const key in tags) {
                    const value = feature.get(key) ?? feature.get('tags')?.[key];
                    if (value !== tags[key]) {
                        matches = false;
                        break;
                    }
                }
                if (matches) {
                    const iconName = PNG_TO_TEMAKI[feat.icon] ?? feat.icon.replace('.png', '');
                    const iconSizePx = (feat.size || 12) * 3.33;
                    return { iconName, iconSizePx };
                }
            }
        }
        return null;
    }

    // Helper to resolve icon name from playground equipment
    function getIconFromPlaygroundEquip(playground, leisure) {
        if (playground && playground !== 'yes' && playground in objDevices) {
            const iconName = DEVICE_ICON_MAP[playground] ?? ICON_MAP[objDevices[playground].category] ?? 'play_structure';
            return { iconName, iconSizePx: 40 };
        }
        if (leisure === 'fitness_station') {
            return { iconName: 'gym', iconSizePx: 40 };
        }
        if (leisure === 'pitch') {
            // Use specific icon based on sport tag for pitches
            const sport = feature.get('sport');
            let iconName;
            if (sport === 'basketball') {
                iconName = 'basketball';
            } else if (sport === 'volleyball') {
                iconName = 'volleyball';
            } else if (!sport) {
                iconName = 'pitch'; // Generic pitch icon when no sport is specified
            } else {
                // For soccer, table_tennis, and any other sport, use generic pitch icon
                // table_soccer is a foosball table, not suitable for soccer fields or tennis
                iconName = 'pitch';
            }
            // Use 40px to match standard equipment icon size
            // All pitch types in objFeatures now use size 12, which gives 40px
            return { iconName, iconSizePx: 40 };
        }
        return null;
    }

    // For Point geometries, use Temaki icons instead of circles (SPEC-636)
    if (geomType === 'Point' || geomType === 'MultiPoint') {
        let result = getIconFromObjFeatures(feature);
        if (!result) result = getIconFromPlaygroundEquip(playground, leisure);
        
        if (result && result.iconName) {
            // Use the category/stroke color for all point icons (including pitches)
            // White icons on green polygons are handled separately in the Polygon section
            const iconColor = strokeColor;
            const iconUrl = getColoredIconUrl(result.iconName, iconColor);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: result.iconSizePx,
                    height: result.iconSizePx,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                })
            });
        }
        
        // Fallback to circle if no icon found
        const radius = (leisure === 'pitch') ? 8 : (leisure === 'fitness_station') ? 7 : 5;
        return new Style({
            image: new Circle({
                radius,
                fill: new Fill({ color: fillColor }),
                stroke: new Stroke({ color: strokeColor, width: 2 })
            })
        });
    }

    if (geomType === 'LineString' || geomType === 'MultiLineString') {
        // For way objects (zipwire, benches, etc.), show icon at center
        let result = getIconFromObjFeatures(feature);
        if (!result) result = getIconFromPlaygroundEquip(playground, leisure);
        
        if (result && result.iconName) {
            const geometry = feature.getGeometry();
            // Use extent to get the center, which works for both LineString and MultiLineString
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            
            // Use the category/stroke color for all line icons (including pitches)
            // White icons on green polygons are handled separately in the Polygon section
            const iconColor = strokeColor;
            const iconUrl = getColoredIconUrl(result.iconName, iconColor);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: result.iconSizePx,
                    height: result.iconSizePx,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                }),
                geometry: pointGeom
            });
        }
        return new Style({ stroke: new Stroke({ color: strokeColor, width: 3 }) });
    }

    // For polygon geometries - render as filled polygons with icons on top for specific types
    // Pitch polygons should keep their polygon rendering
    if (geomType === 'Polygon' || geomType === 'MultiPolygon') {
        // Special case: pitch polygons - show polygon fill + table_soccer icon on top
        if (leisure === 'pitch') {
            const geometry = feature.getGeometry();
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            // Use sport-specific icon for pitch polygons
            const sport = feature.get('sport');
            let iconName;
            if (sport === 'basketball') {
                iconName = 'basketball';
            } else if (sport === 'volleyball') {
                iconName = 'volleyball';
            } else {
                // For soccer, table_tennis, and any other sport, use generic pitch icon
                iconName = 'pitch';
            }
            // Use green color for pitch icons to match equipment list
            // Note: This may reduce visibility on the green polygon, but matches user request
            const iconUrl = getColoredIconUrl(iconName, strokeColor);
            return [
                // Polygon fill/stroke
                new Style({
                    fill: new Fill({ color: fillColor }),
                    stroke: new Stroke({ color: strokeColor, width: 2 })
                }),
                // Icon on top
                new Style({
                    image: new Icon({
                        src: iconUrl,
                        width: 40,
                        height: 40,
                        anchor: [0.5, 0.5],
                        displacement: [0, 0]
                    }),
                    geometry: pointGeom
                })
            ];
        }
        
        // For structure polygons, show icon at centroid
        if (playground === 'structure') {
            const geometry = feature.getGeometry();
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            const iconUrl = getColoredIconUrl('play_structure', strokeColor);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: 40,
                    height: 40,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                }),
                geometry: pointGeom
            });
        }
        
        // For fitness station polygons, show icon at centroid
        if (leisure === 'fitness_station') {
            const geometry = feature.getGeometry();
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            const iconUrl = getColoredIconUrl('gym', objColors.activity);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: 40,
                    height: 40,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                }),
                geometry: pointGeom
            });
        }
        
        // For playground device polygons (sandpits, structures, water devices as areas), show icon at centroid
        if (playground && playground !== 'yes' && playground in objDevices) {
            const iconName = DEVICE_ICON_MAP[playground] ?? ICON_MAP[objDevices[playground].category] ?? 'play_structure';
            const geometry = feature.getGeometry();
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            const iconUrl = getColoredIconUrl(iconName, strokeColor);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: 40,
                    height: 40,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                }),
                geometry: pointGeom
            });
        }
        
        // For objFeatures polygons (shelters, benches, etc. mapped as areas), show icon at centroid
        const result = getIconFromObjFeatures(feature);
        if (result && result.iconName) {
            const geometry = feature.getGeometry();
            const extent = geometry.getExtent();
            const centerX = (extent[0] + extent[2]) / 2;
            const centerY = (extent[1] + extent[3]) / 2;
            const pointGeom = new Point([centerX, centerY]);
            const iconUrl = getColoredIconUrl(result.iconName, strokeColor);
            return new Style({
                image: new Icon({
                    src: iconUrl,
                    width: result.iconSizePx,
                    height: result.iconSizePx,
                    anchor: [0.5, 0.5],
                    displacement: [0, 0]
                }),
                geometry: pointGeom
            });
        }
        
        // Default polygon style for features without specific icon handling
        return new Style({
            fill: new Fill({ color: fillColor }),
            stroke: new Stroke({ color: strokeColor, width: 2 })
        });
    }
    
    return new Style({
        fill: new Fill({ color: fillColor }),
        stroke: new Stroke({ color: strokeColor, width: 2 })
    });
}

/** Style function for equipment vector features (points and polygons). */
export function styleFunction(feature, mode, isPoint) {
    const playground = feature.get('playground');
    let color = objColors.fallback;
    let icon = null;
    let icon_size = null;

    if (mode === 'select') {
        color = '#ff0000';
    } else if (playground in objDevices) {
        const cat = objDevices[playground].category;
        if (cat in objColors) color = objColors[cat];
    } else {
        color = featureColor;
        outer: for (const feat in objFeatures) {
            const tags = objFeatures[feat].tags;
            for (const key in tags) {
                if (feature.get(key) !== tags[key]) continue outer;
            }
            icon = objFeatures[feat].icon;
            icon_size = objFeatures[feat].size;
            break;
        }
    }

    const alpha = playground in objOpacity ? objOpacity[playground] : fillAlpha;
    const [r, g, b] = hexToRgb(color);
    const fill   = `rgba(${r},${g},${b},${alpha})`;
    const stroke = `rgba(${r},${g},${b},${strokeAlpha})`;

    let radius = circleRadius;
    let width  = strokeWidth;
    if (mode === 'select') { radius += 2; width += 2; }
    if (playground === 'sandpit') width -= 1;

    if (isPoint) {
        if (icon) {
            return new Style({
                image: new Icon({ src: `/img/icons/${icon}.png`, width: icon_size })
            });
        }
        return new Style({
            image: new Circle({
                radius,
                fill: new Fill({ color: fill }),
                stroke: new Stroke({ color: stroke, width })
            })
        });
    }
    return new Style({
        fill: new Fill({ color: fill }),
        stroke: new Stroke({ color: stroke, width })
    });
}
